const prompt = `You are a LinkedIn Content Strategist specializing in ${$.input.industry}.

Generate 3 trending, high-engagement LinkedIn post topic ideas for the ${$.input.industry} space.

For each topic provide:
- A compelling title/angle
- Why it's timely and relevant right now
- A suggested hook (first line of the post that stops the scroll)
- Target audience

Then pick the BEST topic and write a complete LinkedIn post with:
- A scroll-stopping first line (hook)
- 150-300 words of valuable content
- Writing style: ${$.input.writingStyle || 'conversational, insightful'}
- A clear call-to-action
- 3-5 relevant hashtags

Return ONLY valid JSON:
{
  "topics": [
    { "title": "...", "rationale": "...", "hook": "...", "audience": "..." }
  ],
  "selected_topic": "title of chosen topic",
  "post_content": "The full LinkedIn post text including hashtags",
  "hashtags": ["#hashtag1", "#hashtag2"]
}`;
return { prompt };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { post_content: raw, topics: [], selected_topic: '', hashtags: [] }; }

const ai = $.steps.parseAI.output || {};
const postText = ai.post_content || 'No content generated.';
return {
  postBody: {
    author: $.input.authorUrn,
    lifecycleState: 'PUBLISHED',
    specificContent: {
      'com.linkedin.ugc.ShareContent': {
        shareCommentary: {
          attributes: [],
          text: postText
        },
        shareMediaCategory: 'NONE'
      }
    },
    visibility: {
      'com.linkedin.ugc.MemberNetworkVisibility': 'PUBLIC'
    }
  },
  postText
};
